args.sparql:
SELECT ?team ?teamLabel WHERE {
  wd:Q10520 p:P54 ?statement.
  ?statement ps:P54 ?team.
  ?statement pq:P580 ?start.
  ?team wdt:P31 wd:Q24052.
  ?team rdfs:label ?teamLabel.
  FILTER (lang(?teamLabel) = "en")
  FILTER NOT EXISTS {
    ?team wdt:P31 wd:Q109825.
  }
} ORDER BY ASC(?start) LIMIT 1
